const body = items[0].json.body || {};
const action = body.action;
let sql = '';

switch(action) {
  case 'enviar_correo':
    sql = `UPDATE mensajes_entrantes SET estado_ticket = 'RESUELTO' WHERE thread_id = '${body.thread_id}'; \n           INSERT INTO mensajes_entrantes (remitente, asunto, mensaje, cuenta_empresa, carpeta, thread_id, leido, de_operador, estado_ticket) \n           SELECT cuenta_empresa, 'Re: ' || asunto, '${body.mensaje}', cuenta_empresa, 'sent', thread_id, true, true, 'RESUELTO' \n           FROM mensajes_entrantes WHERE thread_id = '${body.thread_id}' LIMIT 1 RETURNING *;`;
    break;
  case 'mover_papelera':
    sql = `UPDATE mensajes_entrantes SET carpeta = 'trash' WHERE thread_id = '${body.thread_id}' RETURNING *;`;
    break;
  case 'marcar_leido':
    sql = `UPDATE mensajes_entrantes SET leido = true WHERE thread_id = '${body.thread_id}' RETURNING *;`;
    break;
  case 'asignar_ticket':
    sql = `UPDATE mensajes_entrantes SET asignado_a = ${body.operador ? "'" + body.operador + "'" : 'NULL'}, estado_ticket = ${body.operador ? "'ASIGNADO'" : "'PENDIENTE'"} WHERE thread_id = '${body.thread_id}' RETURNING *;`;
    break;
  case 'guardar_borrador':
    sql = `INSERT INTO mensajes_entrantes (remitente, asunto, mensaje, cuenta_empresa, carpeta, thread_id, leido, de_operador) 
           SELECT cuenta_empresa, 'Re: ' || asunto, '${body.mensaje}', cuenta_empresa, 'drafts', thread_id, true, true 
           FROM mensajes_entrantes WHERE thread_id = '${body.thread_id}' LIMIT 1 RETURNING *;`;
    break;
  case 'crear_grupo':
    sql = `INSERT INTO grupos (nombre, descripcion, tipo, color) VALUES ('${body.nombre}', '${body.descripcion || ''}', '${body.tipo || 'empresa'}', '${body.color || '#4f46e5'}') RETURNING *;`;
    break;
  default:
    sql = 'SELECT 1;';
}

return [{ json: { sql, action } }];
